import { useEffect, useState, useMemo } from 'react';
import Layout from '../components/Layout';
import { bolgeAPI } from '../api';

export default function BolgeStoklar() {
  const [stoklar, setStoklar] = useState([]);
  const [merkezler, setMerkezler] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [seciliMerkez, setSeciliMerkez] = useState('');

  useEffect(() => {
    Promise.all([bolgeAPI.getStoklar(), bolgeAPI.getMerkezler()])
      .then(([s, m]) => {
        setStoklar(s.data);
        setMerkezler(m.data);
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const filtered = useMemo(() => {
    return stoklar.filter(s => {
      const aramaOk = !search ||
        s.urun_adi?.toLowerCase().includes(search.toLowerCase()) ||
        s.merkez_adi?.toLowerCase().includes(search.toLowerCase());
      const merkezOk = !seciliMerkez || s.merkez_adi === seciliMerkez;
      return aramaOk && merkezOk;
    });
  }, [stoklar, search, seciliMerkez]);

  // Merkez bazlı özet
  const merkezOzet = useMemo(() => {
    const ozet = {};
    stoklar.forEach(s => {
      if (!ozet[s.merkez_adi]) ozet[s.merkez_adi] = { toplam: 0, kalem: 0 };
      ozet[s.merkez_adi].toplam += s.adet;
      ozet[s.merkez_adi].kalem += 1;
    });
    return ozet;
  }, [stoklar]);

  return (
    <Layout title="Bölge Stok Durumu">
      {/* Merkez özet kartları */}
      {!loading && (
        <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap', marginBottom: 20 }}>
          <div
            className={`card ${!seciliMerkez ? 'active-card' : ''}`}
            style={{
              padding: '12px 16px', cursor: 'pointer', flex: '0 0 auto',
              border: !seciliMerkez ? '2px solid var(--accent)' : '1px solid var(--border)',
              borderRadius: 8, minWidth: 140
            }}
            onClick={() => setSeciliMerkez('')}
          >
            <div style={{ fontSize: 11, color: 'var(--text3)', textTransform: 'uppercase', letterSpacing: 1 }}>Tüm Merkezler</div>
            <div style={{ fontWeight: 700, fontSize: 18, marginTop: 4 }}>{stoklar.length} kalem</div>
          </div>
          {merkezler.map(m => (
            <div
              key={m.id}
              className="card"
              style={{
                padding: '12px 16px', cursor: 'pointer', flex: '0 0 auto',
                border: seciliMerkez === m.ad ? '2px solid var(--accent)' : '1px solid var(--border)',
                borderRadius: 8, minWidth: 140,
                background: seciliMerkez === m.ad ? 'rgba(249,115,22,0.08)' : 'var(--card)'
              }}
              onClick={() => setSeciliMerkez(seciliMerkez === m.ad ? '' : m.ad)}
            >
              <div style={{ fontSize: 10, color: m.tip === 'toplama' ? 'var(--accent-blue)' : 'var(--accent3)', textTransform: 'uppercase', letterSpacing: 1, marginBottom: 2 }}>
                {m.tip === 'toplama' ? '📦 Toplama' : '🏪 Dağıtım'}
              </div>
              <div style={{ fontWeight: 600, fontSize: 13, marginBottom: 2 }}>{m.ad}</div>
              <div style={{ fontSize: 11, color: 'var(--text3)' }}>{m.il}</div>
              <div style={{ fontWeight: 700, fontSize: 16, color: 'var(--accent)', marginTop: 4 }}>
                {merkezOzet[m.ad]?.kalem || 0} kalem
              </div>
            </div>
          ))}
        </div>
      )}

      <div className="card">
        <div className="card-header">
          <div className="card-title">
            {seciliMerkez ? seciliMerkez : 'Tüm Stoklar'} ({filtered.length})
          </div>
          <input
            className="form-control"
            style={{ width: 200 }}
            placeholder="🔍 Ara..."
            value={search}
            onChange={e => setSearch(e.target.value)}
          />
        </div>

        {loading ? <div className="loading"><div className="spinner" /></div> : (
          filtered.length === 0 ? (
            <div className="empty-state">
              <div className="empty-icon">📦</div>
              <div className="empty-text">Stok bulunamadı</div>
            </div>
          ) : (
            <div className="table-wrapper">
              <table>
                <thead>
                  <tr>
                    <th>Ürün</th>
                    <th>Marka</th>
                    <th>Kategori</th>
                    <th>Adet</th>
                    {!seciliMerkez && <th>Merkez</th>}
                  </tr>
                </thead>
                <tbody>
                  {filtered.map(s => (
                    <tr key={s.id}>
                      <td><strong>{s.urun_adi}</strong></td>
                      <td>{s.marka || '—'}</td>
                      <td>{s.kategori ? <span className="badge badge-neutral">{s.kategori}</span> : '—'}</td>
                      <td>
                        <span style={{
                          fontFamily: 'IBM Plex Mono', fontWeight: 700,
                          color: s.adet <= 10 ? 'var(--danger)' : s.adet <= 50 ? 'var(--warning)' : 'var(--accent3)'
                        }}>{s.adet}</span>
                        <span style={{ color: 'var(--text3)', fontSize: 11 }}> {s.birim}</span>
                      </td>
                      {!seciliMerkez && (
                        <td style={{ fontSize: 12, color: 'var(--text2)' }}>{s.merkez_adi}</td>
                      )}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )
        )}
      </div>
    </Layout>
  );
}
